import { useEffect, useState } from 'react';
import axios from 'axios';
import {
  Container, TextField, Button, Select, MenuItem,
  InputLabel, FormControl, Typography, Paper
} from '@mui/material';

function App() {
  const [clinics, setClinics] = useState([]);

  const [form, setForm] = useState({
    clinic_id: '',
    city: '',
    state: '',
    patient_name: '',
    phone: '',
    channel: 'whatsapp',
    service_type: '',
    description: '',
    criticality: 'media',
    attachment_url: ''
  });

  useEffect(() => {
    axios.get('http://localhost:3001/clinics')
      .then(res => setClinics(res.data));
  }, []);

  const handleClinic = (e) => {
    const clinic = clinics.find(c => c.id == e.target.value);

    setForm({
      ...form,
      clinic_id: clinic.id,
      city: clinic.city,
      state: clinic.state
    });
  };

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const salvar = async () => {
    try {
      await axios.post('http://localhost:3001/complaints', form);
      alert('Salvo com sucesso!');
    } catch {
      alert('Erro');
    }
  };

  return (
    <Container maxWidth="sm">
      <Paper style={{ padding: 20, marginTop: 40 }}>
        <Typography variant="h5">Cadastro de Reclamação</Typography>

        <FormControl fullWidth margin="normal">
          <InputLabel>Clínica</InputLabel>
          <Select onChange={handleClinic}>
            {clinics.map(c => (
              <MenuItem key={c.id} value={c.id}>{c.name}</MenuItem>
            ))}
          </Select>
        </FormControl>

        <TextField fullWidth margin="normal" value={form.city} label="Cidade" disabled />
        <TextField fullWidth margin="normal" value={form.state} label="Estado" disabled />

        <TextField fullWidth margin="normal" name="patient_name" label="Paciente" onChange={handleChange} />
        <TextField fullWidth margin="normal" name="phone" label="Telefone" onChange={handleChange} />

        <FormControl fullWidth margin="normal">
          <InputLabel>Canal</InputLabel>
          <Select name="channel" onChange={handleChange}>
            <MenuItem value="whatsapp">WhatsApp</MenuItem>
            <MenuItem value="email">Email</MenuItem>
            <MenuItem value="google">Google</MenuItem>
          </Select>
        </FormControl>

        <FormControl fullWidth margin="normal">
          <InputLabel>Serviço</InputLabel>
          <Select name="service_type" onChange={handleChange}>
            <MenuItem>Clínico Geral</MenuItem>
            <MenuItem>Ortodontia</MenuItem>
            <MenuItem>Implante</MenuItem>
            <MenuItem>Endodontia</MenuItem>
          </Select>
        </FormControl>

        <TextField fullWidth multiline rows={3} margin="normal" name="description" label="Descrição" onChange={handleChange} />

        <Button variant="contained" color="primary" onClick={salvar}>
          Salvar
        </Button>
      </Paper>
    </Container>
  );
}

export default App;
